// QueryResultTable.tsx
import { useState, useRef, useEffect } from 'react';
export function QueryResultTable<R extends { id: string }>({ rows, columns, persistKey }: { rows: ReadonlyArray<R>; columns: ReadonlyArray<{ id: string; label: string; accessor: (r: R) => string }>; persistKey: string }) {
  const [widths, setWidths] = useState<Record<string, number>>(() => { try { return JSON.parse(localStorage.getItem(`${persistKey}-widths`) ?? '{}'); } catch { return {}; } });
  const [order, setOrder] = useState<string[]>(() => { try { const saved = JSON.parse(localStorage.getItem(`${persistKey}-order`) ?? 'null'); return saved ?? columns.map(c => c.id); } catch { return columns.map(c => c.id); } });
  useEffect(() => { try { localStorage.setItem(`${persistKey}-widths`, JSON.stringify(widths)); } catch {} }, [widths, persistKey]);
  useEffect(() => { try { localStorage.setItem(`${persistKey}-order`, JSON.stringify(order)); } catch {} }, [order, persistKey]);
  const orderedCols = order.map(id => columns.find(c => c.id === id)).filter(Boolean) as typeof columns;
  const onResizeStart = (id: string, e: React.MouseEvent) => {
    const startX = e.clientX; const startW = widths[id] ?? 120;
    const onMove = (ev: MouseEvent) => { setWidths(w => ({ ...w, [id]: Math.max(60, startW + ev.clientX - startX) })); };
    const onUp = () => { document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
    document.addEventListener('mousemove', onMove); document.addEventListener('mouseup', onUp);
  };
  return (
    <table className="border-collapse text-[12px] font-mono">
      <thead><tr>{orderedCols.map(c => <th key={c.id} className="relative text-left text-[10px] uppercase tracking-wider font-semibold px-3 py-1.5 text-[oklch(0.55_0.005_250)] border-b border-[oklch(0.92_0.005_250)] bg-[oklch(0.97_0.005_250)]" style={{ width: widths[c.id] ?? 120 }}>{c.label}<span onMouseDown={(e) => onResizeStart(c.id, e)} className="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-[oklch(0.55_0.18_250)]" /></th>)}</tr></thead>
      <tbody>{rows.map(r => <tr key={r.id} className="border-b border-[oklch(0.95_0.005_250)]">{orderedCols.map(c => <td key={c.id} className="px-3 py-1" style={{ width: widths[c.id] ?? 120 }}>{c.accessor(r)}</td>)}</tr>)}</tbody>
    </table>
  );
}

// QuickSwitcher.tsx
import { useState, useMemo } from 'react';
export function QuickSwitcher({ files, recent, onOpen, open, onClose }: { files: ReadonlyArray<{ path: string; name: string }>; recent: ReadonlyArray<string>; onOpen: (path: string) => void; open: boolean; onClose: () => void }) {
  const [query, setQuery] = useState('');
  const [focusIdx, setFocusIdx] = useState(0);
  const results = useMemo(() => {
    if (!query) return recent.map(p => files.find(f => f.path === p)).filter(Boolean).slice(0, 8) as typeof files;
    const q = query.toLowerCase();
    return files.filter(f => f.name.toLowerCase().includes(q) || f.path.toLowerCase().includes(q)).slice(0, 16);
  }, [files, recent, query]);
  if (!open) return null;
  return (
    <div role="dialog" className="fixed inset-0 z-50 flex items-start justify-center pt-[12vh] bg-black/40" onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} className="w-[480px] bg-white rounded-lg shadow-2xl overflow-hidden">
        <input autoFocus value={query} onChange={(e) => { setQuery(e.target.value); setFocusIdx(0); }} onKeyDown={(e) => { if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(results.length - 1, i + 1)); } else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); } else if (e.key === 'Enter') { e.preventDefault(); const f = results[focusIdx]; if (f) { onOpen(f.path); onClose(); } } }} placeholder="Search files\u2026" className="w-full h-11 px-4 outline-none text-[14px] border-b border-[oklch(0.93_0.005_250)]" />
        {!query && <div className="px-4 py-1.5 text-[10px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] bg-[oklch(0.97_0.005_250)]">Recent</div>}
        <ul className="max-h-[400px] overflow-y-auto">
          {results.map((f, i) => <li key={f.path} role="option" aria-selected={i === focusIdx} onMouseEnter={() => setFocusIdx(i)} onClick={() => { onOpen(f.path); onClose(); }} className={`px-4 py-2 cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.94_0.04_250)]' : ''}`}>
            <div className="text-[13px] font-mono">{f.name}</div>
            <div className="text-[11px] text-[oklch(0.55_0.005_250)] font-mono">{f.path}</div>
          </li>)}
        </ul>
      </div>
    </div>
  );
}

