// BoxPlot.tsx
export interface BoxPlotGroup { id: string; label: string; values: ReadonlyArray<number>; }
function quantile(sorted: ReadonlyArray<number>, q: number): number { const pos = (sorted.length - 1) * q; const base = Math.floor(pos); const rest = pos - base; return sorted[base + 1] !== undefined ? sorted[base] + rest * (sorted[base + 1] - sorted[base]) : sorted[base]; }
export function BoxPlot({ groups, width = 480, height = 280 }: { groups: ReadonlyArray<BoxPlotGroup>; width?: number; height?: number }) {
  const all = groups.flatMap(g => g.values);
  const min = Math.min(...all), max = Math.max(...all);
  const range = max - min || 1;
  const yScale = (v: number) => height - 30 - ((v - min) / range) * (height - 60);
  const groupWidth = width / groups.length;
  return (
    <svg width={width} height={height}>
      {groups.map((g, i) => {
        const sorted = [...g.values].sort((a, b) => a - b);
        const q1 = quantile(sorted, 0.25), q2 = quantile(sorted, 0.5), q3 = quantile(sorted, 0.75);
        const iqr = q3 - q1; const lowFence = q1 - 1.5 * iqr; const highFence = q3 + 1.5 * iqr;
        const wMin = sorted.find(v => v >= lowFence) ?? q1; const wMax = [...sorted].reverse().find(v => v <= highFence) ?? q3;
        const outliers = sorted.filter(v => v < lowFence || v > highFence);
        const cx = i * groupWidth + groupWidth / 2;
        return (
          <g key={g.id}>
            <line x1={cx} y1={yScale(wMin)} x2={cx} y2={yScale(wMax)} stroke="oklch(0.55 0.18 250)" />
            <rect x={cx - 16} y={yScale(q3)} width={32} height={yScale(q1) - yScale(q3)} fill="oklch(0.55 0.18 250 / 0.3)" stroke="oklch(0.55 0.18 250)" />
            <line x1={cx - 16} y1={yScale(q2)} x2={cx + 16} y2={yScale(q2)} stroke="oklch(0.55 0.18 250)" strokeWidth="2" />
            {outliers.map((v, j) => <circle key={j} cx={cx} cy={yScale(v)} r={3} fill="oklch(0.55 0.18 250)" />)}
            <text x={cx} y={height - 8} fontSize="11" textAnchor="middle" fill="oklch(0.55 0.005 250)">{g.label}</text>
          </g>
        );
      })}
    </svg>
  );
}

