import { useState, useEffect } from 'react';
export interface DemoStep { x: number; y: number; action?: 'click'; pauseMs?: number; }
export function DemoCursor({ sequence, onUserTakeover }: { sequence: ReadonlyArray<DemoStep>; onUserTakeover: () => void }) {
  const [stepIdx, setStepIdx] = useState(0);
  const [pos, setPos] = useState({ x: sequence[0]?.x ?? 0, y: sequence[0]?.y ?? 0 });
  useEffect(() => {
    const onUserClick = () => onUserTakeover();
    window.addEventListener('click', onUserClick);
    return () => window.removeEventListener('click', onUserClick);
  }, [onUserTakeover]);
  useEffect(() => {
    const step = sequence[stepIdx]; if (!step) return;
    setPos({ x: step.x, y: step.y });
    const t = window.setTimeout(() => setStepIdx(i => (i + 1) % sequence.length), 1500 + (step.pauseMs ?? 0));
    return () => window.clearTimeout(t);
  }, [stepIdx, sequence]);
  return (
    <div aria-hidden="true" className="fixed pointer-events-none z-50" style={{ left: pos.x, top: pos.y, transition: 'left 1200ms cubic-bezier(0.65, 0, 0.35, 1), top 1200ms cubic-bezier(0.65, 0, 0.35, 1)' }}>
      <svg width="16" height="18" viewBox="0 0 16 18"><path d="M0 0 L0 13 L4 10 L7 17 L9 16 L6 9 L11 9 Z" fill="oklch(0.55 0.18 250)" stroke="white" strokeWidth="1.5" /></svg>
    </div>
  );
}

