import { useState, useEffect } from 'react';
export function MultiSourceFileInput({ onFiles }: { onFiles: (files: ReadonlyArray<File>) => void }) {
  const [over, setOver] = useState(false);
  useEffect(() => {
    const onPaste = (e: ClipboardEvent) => {
      const items = Array.from(e.clipboardData?.items ?? []);
      const files = items.filter(i => i.kind === 'file').map(i => i.getAsFile()).filter(Boolean) as File[];
      if (files.length > 0) onFiles(files);
    };
    window.addEventListener('paste', onPaste);
    return () => window.removeEventListener('paste', onPaste);
  }, [onFiles]);
  return (
    <div onDragOver={(e) => { e.preventDefault(); setOver(true); }} onDragLeave={() => setOver(false)} onDrop={(e) => { e.preventDefault(); setOver(false); onFiles(Array.from(e.dataTransfer.files)); }}
      className={`h-30 border-2 border-dashed rounded-md flex flex-col items-center justify-center transition-colors duration-[150ms] ${over ? 'border-[oklch(0.55_0.18_250)] bg-[oklch(0.94_0.04_250)]' : 'border-[oklch(0.85_0.005_250)]'}`}>
      <p className="text-[14px] text-[oklch(0.55_0.005_250)]">Drop files, paste, or <label className="text-[oklch(0.55_0.18_250)] cursor-pointer">browse<input type="file" multiple className="hidden" onChange={(e) => onFiles(Array.from(e.target.files ?? []))} /></label></p>
    </div>
  );
}

