import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { CatmullRomCurve3, Vector3 } from 'three';
import { useRef, useEffect, useMemo } from 'react';
export function ScrollScene({ pathPoints, scrollRef }: { pathPoints: ReadonlyArray<[number, number, number]>; scrollRef: { current: number } }) {
  return (
    <Canvas camera={{ position: pathPoints[0], fov: 40 }}>
      <ambientLight intensity={0.5} />
      <CameraOnScrollPath pathPoints={pathPoints} scrollRef={scrollRef} />
      {/* scene contents */}
    </Canvas>
  );
}
function CameraOnScrollPath({ pathPoints, scrollRef }: { pathPoints: ReadonlyArray<[number, number, number]>; scrollRef: { current: number } }) {
  const { camera } = useThree();
  const curve = useMemo(() => new CatmullRomCurve3(pathPoints.map(p => new Vector3(...p))), [pathPoints]);
  useFrame(() => {
    const t = Math.max(0, Math.min(1, scrollRef.current));
    const pos = curve.getPoint(t);
    camera.position.copy(pos);
    camera.lookAt(0, 0, 0);
  });
  return null;
}

