// RadioGroup.tsx
import { useRef } from 'react';
export function RadioGroup({ value, onChange, options, label }: { value: string; onChange: (v: string) => void; options: ReadonlyArray<{ value: string; label: string }>; label: string }) {
  const refs = useRef<HTMLButtonElement[]>([]);
  const selectedIdx = options.findIndex(o => o.value === value);
  const onKey = (e: React.KeyboardEvent, idx: number) => {
    if (e.key === 'ArrowDown' || e.key === 'ArrowRight') { e.preventDefault(); const next = (idx + 1) % options.length; onChange(options[next].value); refs.current[next]?.focus(); }
    else if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') { e.preventDefault(); const next = (idx - 1 + options.length) % options.length; onChange(options[next].value); refs.current[next]?.focus(); }
  };
  return (
    <div role="radiogroup" aria-label={label}>
      {options.map((o, i) => {
        const selected = o.value === value;
        return (
          <button key={o.value} ref={(el) => { if (el) refs.current[i] = el; }} type="button" role="radio" aria-checked={selected} tabIndex={(selectedIdx === -1 ? i === 0 : selected) ? 0 : -1} onClick={() => onChange(o.value)} onKeyDown={(e) => onKey(e, i)} className="flex items-center gap-2 px-3 py-1.5 text-[14px] hover:bg-[oklch(0.97_0.005_250)] w-full text-left">
            <span className="w-4 h-4 rounded-full border-2 flex items-center justify-center" style={{ borderColor: selected ? 'oklch(0.55 0.18 250)' : 'oklch(0.7 0.005 250)' }}>
              {selected && <span className="w-2 h-2 rounded-full bg-[oklch(0.55_0.18_250)]" />}
            </span>
            {o.label}
          </button>
        );
      })}
    </div>
  );
}

// LazyTabs.tsx
import { useState } from 'react';
export function LazyTabs({ tabs, defaultActiveId }: { tabs: ReadonlyArray<{ id: string; label: string; render: () => React.ReactNode }>; defaultActiveId?: string }) {
  const [activeId, setActiveId] = useState(defaultActiveId ?? tabs[0]?.id);
  const activeIdx = tabs.findIndex(t => t.id === activeId);
  const mountedIndices = new Set([activeIdx, activeIdx - 1, activeIdx + 1].filter(i => i >= 0 && i < tabs.length));
  return (
    <div>
      <div role="tablist" className="flex border-b border-[oklch(0.92_0.005_250)]">
        {tabs.map(t => <button key={t.id} type="button" role="tab" aria-selected={t.id === activeId} onClick={() => setActiveId(t.id)} className={`h-10 px-3 text-[14px] font-medium border-b-2 ${t.id === activeId ? 'border-[oklch(0.55_0.18_250)]' : 'border-transparent text-[oklch(0.55_0.005_250)]'}`}>{t.label}</button>)}
      </div>
      {tabs.map((t, i) => mountedIndices.has(i) && <div key={t.id} role="tabpanel" hidden={t.id !== activeId} className="p-4">{t.render()}</div>)}
    </div>
  );
}

