// DatePicker.tsx
import { useState } from 'react';
export function DatePicker({ value, onChange }: { value: Date | null; onChange: (d: Date) => void }) {
  const [viewMonth, setViewMonth] = useState(new Date(value ?? new Date()));
  const [focused, setFocused] = useState(value ?? new Date());
  const onKey = (e: React.KeyboardEvent) => {
    let next = new Date(focused);
    if (e.key === 'ArrowRight') next.setDate(next.getDate() + 1);
    else if (e.key === 'ArrowLeft') next.setDate(next.getDate() - 1);
    else if (e.key === 'ArrowDown') next.setDate(next.getDate() + 7);
    else if (e.key === 'ArrowUp') next.setDate(next.getDate() - 7);
    else if (e.key === 'PageDown') next.setMonth(next.getMonth() + 1);
    else if (e.key === 'PageUp') next.setMonth(next.getMonth() - 1);
    else if ((e.metaKey || e.ctrlKey) && e.key === 't') next = new Date();
    else if (e.key === 'Enter') { onChange(focused); return; }
    else return;
    e.preventDefault();
    setFocused(next);
    setViewMonth(next);
  };
  const firstOfMonth = new Date(viewMonth.getFullYear(), viewMonth.getMonth(), 1);
  const days = new Date(viewMonth.getFullYear(), viewMonth.getMonth() + 1, 0).getDate();
  const leading = firstOfMonth.getDay();
  const cells: Array<Date | null> = [];
  for (let i = 0; i < leading; i++) cells.push(null);
  for (let d = 1; d <= days; d++) cells.push(new Date(viewMonth.getFullYear(), viewMonth.getMonth(), d));
  const today = new Date();
  return (
    <div tabIndex={0} onKeyDown={onKey} className="outline-none" role="grid">
      <div className="text-[13px] font-medium mb-2">{viewMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</div>
      <div className="grid grid-cols-7 gap-1">
        {cells.map((d, i) => { if (!d) return <div key={i} />; const isFocus = d.toDateString() === focused.toDateString(); const isSel = value && d.toDateString() === value.toDateString(); const isToday = d.toDateString() === today.toDateString(); return (
          <button key={i} type="button" onClick={() => { setFocused(d); onChange(d); }} className={`h-8 text-[13px] tabular-nums rounded ${isSel ? 'bg-[oklch(0.55_0.18_250)] text-white' : isFocus ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'}`} style={{ outline: isToday ? '1px solid oklch(0.55 0.18 250)' : undefined }}>{d.getDate()}</button>
        ); })}
      </div>
    </div>
  );
}

