import { useState, useRef, useEffect } from 'react';
export function Tooltip({ content, children }: { content: string; children: React.ReactElement }) {
  const [hovered, setHovered] = useState(false);
  const [show, setShow] = useState(false);
  const triggerRef = useRef<HTMLElement | null>(null);
  const [rect, setRect] = useState<DOMRect | null>(null);
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    if (hovered) { timerRef.current = window.setTimeout(() => { setShow(true); if (triggerRef.current) setRect(triggerRef.current.getBoundingClientRect()); }, 350); }
    else { if (timerRef.current) window.clearTimeout(timerRef.current); setShow(false); }
    return () => { if (timerRef.current) window.clearTimeout(timerRef.current); };
  }, [hovered]);
  const child = children as React.ReactElement<any>;
  return (
    <>
      {/* Clone child to attach hover handlers + ref */}
      <span ref={(el) => { triggerRef.current = el; }} onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)} onFocus={() => setHovered(true)} onBlur={() => setHovered(false)}>{child}</span>
      {show && rect && (
        <div role="tooltip" className="fixed z-50 px-2.5 py-1.5 bg-[oklch(0.18_0.005_250)] text-white text-[12px] rounded" style={{ top: rect.top + window.scrollY - 36, left: rect.left + window.scrollX + rect.width / 2, transform: 'translateX(-50%)', animation: 'tipIn 80ms ease-out' }}>
