          <style>{`@keyframes tipIn { from { opacity: 0; transform: translate(-50%, 2px) } to { opacity: 1; transform: translate(-50%, 0) } } @media (prefers-reduced-motion: reduce) { [style*='tipIn'] { animation: none !important } }`}</style>
