// CandleChart.tsx
import { useState } from 'react';
export interface Candle { time: number; open: number; high: number; low: number; close: number; }
export function CandleChart({ candles, width = 600, height = 280 }: { candles: ReadonlyArray<Candle>; width?: number; height?: number }) {
  const [hoverIdx, setHoverIdx] = useState<number | null>(null);
  const allValues = candles.flatMap(c => [c.high, c.low]);
  const min = Math.min(...allValues), max = Math.max(...allValues);
  const yScale = (v: number) => height - 30 - ((v - min) / (max - min)) * (height - 60);
  const cw = width / candles.length;
  const hovered = hoverIdx != null ? candles[hoverIdx] : null;
  return (
    <div className="relative" onMouseLeave={() => setHoverIdx(null)}>
      {hovered && <div className="absolute top-0 left-0 right-0 text-[11px] tabular-nums text-[oklch(0.45_0.005_250)] flex gap-3"><span>O {hovered.open}</span><span>H {hovered.high}</span><span>L {hovered.low}</span><span>C {hovered.close}</span></div>}
      <svg width={width} height={height} onMouseMove={(e) => { const r = e.currentTarget.getBoundingClientRect(); setHoverIdx(Math.floor((e.clientX - r.left) / cw)); }}>
        {candles.map((c, i) => { const x = i * cw + cw / 2; const up = c.close >= c.open; const color = up ? 'oklch(0.55 0.14 145)' : 'oklch(0.6 0.18 25)'; const bodyTop = yScale(Math.max(c.open, c.close)); const bodyBot = yScale(Math.min(c.open, c.close)); return (
          <g key={i}>
            <line x1={x} y1={yScale(c.high)} x2={x} y2={yScale(c.low)} stroke={color} strokeWidth="1" />
            <rect x={x - cw / 3} y={bodyTop} width={cw * 2/3} height={Math.max(1, bodyBot - bodyTop)} fill={color} />
          </g>
        ); })}
        {hoverIdx != null && <line x1={hoverIdx * cw + cw / 2} y1={0} x2={hoverIdx * cw + cw / 2} y2={height} stroke="oklch(0.55 0.005 250)" strokeDasharray="2 2" />}
      </svg>
    </div>
  );
}

