// RangeSlider.tsx
import { useRef } from 'react';
export function RangeSlider({ min, max, value, onChange, step = 1 }: { min: number; max: number; value: [number, number]; onChange: (v: [number, number]) => void; step?: number }) {
  const trackRef = useRef<HTMLDivElement | null>(null);
  const pct = (v: number) => ((v - min) / (max - min)) * 100;
  const onThumbKey = (idx: 0 | 1, e: React.KeyboardEvent) => {
    const delta = e.key === 'ArrowRight' || e.key === 'ArrowUp' ? step : e.key === 'ArrowLeft' || e.key === 'ArrowDown' ? -step : 0;
    if (delta === 0) return; e.preventDefault();
    const newVal: [number, number] = [...value] as [number, number];
    newVal[idx] = Math.max(min, Math.min(max, value[idx] + delta));
    if (idx === 0 && newVal[0] > value[1]) newVal[0] = value[1];
    if (idx === 1 && newVal[1] < value[0]) newVal[1] = value[0];
    onChange(newVal);
  };
  return (
    <div className="relative h-6">
      <div ref={trackRef} className="absolute top-2.5 left-0 right-0 h-1 bg-[oklch(0.92_0.005_250)] rounded">
        <div className="absolute top-0 bottom-0 bg-[oklch(0.55_0.18_250)]" style={{ left: `${pct(value[0])}%`, right: `${100 - pct(value[1])}%` }} />
      </div>
      {[0, 1].map(idx => <button key={idx} type="button" role="slider" aria-valuenow={value[idx as 0 | 1]} aria-valuemin={min} aria-valuemax={max} onKeyDown={(e) => onThumbKey(idx as 0 | 1, e)} className="absolute top-0 w-5 h-5 -ml-2.5 rounded-full bg-white border-2 border-[oklch(0.55_0.18_250)] shadow" style={{ left: `${pct(value[idx as 0 | 1])}%` }} />)}
    </div>
  );
}

