// MultiSelectListbox.tsx
import { useState } from 'react';
export function MultiSelectListbox<T extends { id: string; label: string }>({ items, selectedIds, onChange }: { items: ReadonlyArray<T>; selectedIds: Set<string>; onChange: (next: Set<string>) => void }) {
  const [anchor, setAnchor] = useState<string | null>(null);
  const onItemClick = (id: string, e: React.MouseEvent) => {
    if (e.shiftKey && anchor) {
      const ai = items.findIndex(i => i.id === anchor); const ci = items.findIndex(i => i.id === id);
      if (ai >= 0 && ci >= 0) { const [lo, hi] = ai < ci ? [ai, ci] : [ci, ai]; const next = new Set(selectedIds); for (let i = lo; i <= hi; i++) next.add(items[i].id); onChange(next); }
    } else if (e.metaKey || e.ctrlKey) {
      const next = new Set(selectedIds); if (next.has(id)) next.delete(id); else next.add(id); onChange(next); setAnchor(id);
    } else {
      onChange(new Set([id])); setAnchor(id);
    }
  };
  return (
    <ul role="listbox" aria-multiselectable="true" tabIndex={0} className="outline-none border border-[oklch(0.92_0.005_250)] rounded">
      {items.map(item => <li key={item.id} role="option" aria-selected={selectedIds.has(item.id)} onClick={(e) => onItemClick(item.id, e)} className={`px-3 py-1.5 cursor-pointer text-[14px] ${selectedIds.has(item.id) ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'}`}>{item.label}</li>)}
    </ul>
  );
}

