// WorkspaceRail.tsx
import { useEffect } from 'react';
export function WorkspaceRail({ workspaces, activeId, onSwitch }: { workspaces: ReadonlyArray<{ id: string; name: string; color: string }>; activeId: string; onSwitch: (id: string) => void }) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey) || e.shiftKey) return;
      const n = parseInt(e.key, 10);
      if (!isNaN(n) && n >= 1 && n <= 9 && workspaces[n - 1]) { e.preventDefault(); onSwitch(workspaces[n - 1].id); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [workspaces, onSwitch]);
  return (
    <nav aria-label="Workspaces" className="w-12 bg-[oklch(0.18_0.005_250)] p-2 flex flex-col gap-2">
      {workspaces.map((w, i) => <button key={w.id} type="button" onClick={() => onSwitch(w.id)} title={`${w.name} (\u2318${i + 1})`} className="w-8 h-8 rounded-md flex items-center justify-center text-white text-[12px] font-bold" style={{ background: w.color, outline: activeId === w.id ? '2px solid white' : 'none', outlineOffset: '2px' }}>{w.name[0]}</button>)}
    </nav>
  );
}

// useTabUnreadCounter.ts
import { useEffect } from 'react';
export function useTabUnreadCounter(count: number, baseTitle: string) {
  useEffect(() => {
    document.title = count > 0 && document.hidden ? `(${count}) ${baseTitle}` : baseTitle;
  }, [count, baseTitle]);
  useEffect(() => {
    const onVis = () => { document.title = count > 0 && document.hidden ? `(${count}) ${baseTitle}` : baseTitle; };
    document.addEventListener('visibilitychange', onVis);
    return () => document.removeEventListener('visibilitychange', onVis);
  }, [count, baseTitle]);
}

